using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        optionsBuilder.UseCosmos(
            "AccountEndpoint=...;AccountKey=...",
            "YourDatabase");
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // BREAKING CHANGE 1: EF 9 renamed the discriminator JSON property from
            // "Discriminator" to "$type". Revert so existing documents and direct SQL
            // queries (WHERE c.Discriminator = 'Product') keep working.
            b.HasDiscriminator<string>("Discriminator");
            b.Property("Discriminator").ToJsonProperty("Discriminator");

            // BREAKING CHANGE 2: EF 9 no longer prepends the entity-type name to the
            // id value. Old format: "Product|123", new default: "123".
            // Include the root discriminator in the JSON id to preserve the old format.
            b.HasRootDiscriminatorInJsonId();
        });
    }
}

class Product { public int Id { get; set; } public string Sku { get; set; } }

