using Microsoft.EntityFrameworkCore.ValueGeneration;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        // Preserve EF Core 8 id format ("Product|123") and discriminator property name ("Discriminator")
        // so existing 500K documents remain readable without a data migration.
        optionsBuilder.UseCosmos(
            "AccountEndpoint=...;AccountKey=...",
            "YourDatabase",
            cosmosOptions => cosmosOptions.HasDefaultIdValueGeneration());
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF 9 renamed the discriminator from "Discriminator" to "$type".
        // Revert to the old property name so existing documents and direct SQL queries still work.
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");
            b.HasDiscriminatorInJsonProperty("Discriminator");

            // EF 9 changed id synthesis from "Product|<key>" to just "<key>".
            // Preserve the old format so existing documents are still found.
            b.HasIdProperty("id", id => id.HasValueGenerator<LegacyIdValueGenerator>());
        });
    }
}

